SELECT id, group_id, session_date, data_locked, locked_by, locked_at, created_by, created_at
FROM daily_sessions
WHERE group_id = #{groupId} AND session_date = #{sessionDate}

SELECT id, group_id, session_date, data_locked, locked_by, locked_at, created_by, created_at
FROM daily_sessions
WHERE group_id = #{groupId}
  AND session_date >= #{from}
  AND session_date <= #{to}
ORDER BY session_date DESC

mapper.update:
UPDATE daily_sessions
SET data_locked = #{dataLocked},
    locked_by   = #{lockedBy},
    locked_at   = #{lockedAt}
WHERE id = #{id}
